 6→export default async function CustomerQrPage() {
 7→  const supabase = await createServerSupabase();
 8→  const { data: { user } } = await supabase.auth.getUser();
 9→
10→  // Get or create customer QR code
11→  let { data: qrCode } = await supabase
12→    .from('customer_qr_codes')
13→    .select('*')
14→    .eq('customer_id', user!.id)
15→    .eq('is_active', true)
