 3→import { QRCode } from 'react-qrcode-logo';
 4→import Card from '@/components/ui/Card';
 5→import { RefreshCw } from 'lucide-react';
 6→import { useState, useEffect } from 'react';
 7→
 8→interface CustomerQrDisplayProps {
 9→  qrId: string;
10→  secretKey: string;
11→  appUrl: string;
12→}
13→
14→export default function CustomerQrDisplay({ qrId, secretKey, appUrl }: CustomerQrDisplayProps) {
15→  // Rotate the displayed code every 30 seconds for security
16→  const [timestamp, setTimestamp] = useState(() => Math.floor(Date.now() / 30000));
17→  const [secondsLeft, setSecondsLeft] = useState(30);
18→
19→  useEffect(() => {
20→    const interval = setInterval(() => {
21→      const now = Date.now();
22→      const currentSlot = Math.floor(now / 30000);
23→      const remaining = 30 - Math.floor((now % 30000) / 1000);
24→      setTimestamp(currentSlot);
25→      setSecondsLeft(remaining);
26→    }, 1000);
27→    return () => clearInterval(interval);
28→  }, []);
29→
30→  // The QR payload: customer QR ID + time-based token
31→  const qrPayload = JSON.stringify({
32→    type: 'customer',
33→    id: qrId,
34→    key: secretKey,
35→    t: timestamp,
36→  });
37→
38→  return (
39→    <div className="space-y-4">
40→      <Card padding="lg" className="flex flex-col items-center space-y-4">
41→        <p className="text-[13px] text-[var(--text-secondary)] text-center">
42→          Presentez ce QR code au marchand pour gagner des points ou tampons.
43→        </p>
44→
45→        <div className="bg-white p-3 rounded-xl">
46→          <QRCode
47→            value={qrPayload}
48→            size={220}
49→            qrStyle="dots"
50→            eyeRadius={8}
51→            fgColor="#1a1a2e"
52→            bgColor="#ffffff"
53→          />
54→        </div>
55→
56→        <div className="flex items-center gap-2 text-[12px] text-[var(--text-tertiary)]">
57→          <RefreshCw className="w-3.5 h-3.5 animate-spin" style={{ animationDuration: '3s' }} />
58→          <span>Actualisation dans {secondsLeft}s</span>
59→        </div>
60→
61→        <p className="text-[11px] text-[var(--text-tertiary)] text-center">
62→          Code unique : {qrId.slice(0, 8).toUpperCase()}
63→        </p>
64→      </Card>
65→
66→      <Card padding="md">
67→        <h3 className="text-[13px] font-semibold text-[var(--text-primary)] mb-2">Comment ca marche ?</h3>
68→        <ol className="text-[12px] text-[var(--text-secondary)] space-y-1.5 list-decimal list-inside">
69→          <li>Le marchand ouvre son scanner</li>
70→          <li>Il scanne votre QR code</li>
71→          <li>Vos points ou tampons sont credites automatiquement</li>
72→        </ol>
73→      </Card>
74→    </div>
75→  );
76→}
