10→
11→export default function ScanHandler({ qrCode, userId }: { qrCode: any; userId: string }) {
12→  const router = useRouter();
13→  const [status, setStatus] = useState<'loading' | 'enrolled' | 'already'>('loading');
14→
15→  useEffect(() => {
16→    const enroll = async () => {
17→      const supabase = createClient();
18→      const program = qrCode.loyalty_programs;
19→
20→      // Check if already enrolled
21→      const { data: existing } = await supabase
22→        .from('customer_cards')
23→        .select('id')
24→        .eq('customer_id', userId)
25→        .eq('program_id', program.id)
26→        .single();
27→
28→      if (existing) {
29→        setStatus('already');
30→        return;
31→      }
32→
33→      // Ensure customer record exists
34→      await supabase.from('customers').upsert({ id: userId, email: '' }, { onConflict: 'id' });
35→
36→      // Create card with welcome bonus
37→      const { error } = await supabase.from('customer_cards').insert({
38→        customer_id: userId,
39→        program_id: program.id,
40→        balance: program.welcome_bonus || 0,
41→      });
42→
43→      if (error) { toast.error(error.message); return; }
44→
45→      // Log welcome bonus transaction
46→      if (program.welcome_bonus > 0) {
47→        const { data: newCard } = await supabase
48→          .from('customer_cards')
49→          .select('id')
50→          .eq('customer_id', userId)
51→          .eq('program_id', program.id)
52→          .single();
53→
54→        if (newCard) {
55→          await supabase.from('transactions').insert({
56→            card_id: newCard.id,
57→            merchant_id: program.merchant_id,
58→            type: 'earn',
59→            amount: program.welcome_bonus,
60→            source: 'qr',
61→          });
62→        }
63→      }
64→
65→      setStatus('enrolled');
66→      toast.success(`+${program.welcome_bonus} bonus de bienvenue !`);
67→    };
68→
69→    enroll();
70→  }, [qrCode, userId]);
71→
72→  const program = qrCode.loyalty_programs;
73→  const merchant = program.merchants;
74→
75→  return (
76→    <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)] p-4">
77→      <Card padding="lg" className="max-w-sm w-full text-center space-y-4 page-enter">
78→        <CheckCircle className="w-12 h-12 text-[var(--accent)] mx-auto" />
79→        <h2 className="text-xl font-bold text-[var(--text-primary)]">{merchant.business_name}</h2>
80→        <p className="text-[var(--text-secondary)]">
81→          {status === 'enrolled' && `Inscrit au programme "${program.name}" ! Bonus: +${program.welcome_bonus}`}
82→          {status === 'already' && `Vous etes deja inscrit au programme "${program.name}".`}
83→          {status === 'loading' && 'Inscription en cours...'}
84→        </p>
85→        <Button onClick={() => router.push('/customer')} className="w-full">Voir mes cartes</Button>
86→      </Card>
87→    </div>
88→  );
89→}
